1	// Deterministic GH posting: resolve PR, fetch diff, run inline, post inline review,
2	// render summary, upsert sticky comment. Pure core with a thin gh-api effect.
3	//
4	// Ordering (CO-R3): all reads, decodes, diff validation, and rendering complete before
5	// the first API write; then the sticky is posted, and the inline review second. A posting
6	// failure propagates and exits the process non-zero (never partially posts).
7	
8	import { readFileSync } from "node:fs";
9	import type { InlineComment, InlineDisposition, RenderInput } from "./types.js";
10	import { buildInlineComments } from "./inline.js";
11	import { isEmptyDiff } from "./diff.js";
12	import { render, computeSeverityCounts } from "./render.js";
13	import { formatMarkdown } from "./format.js";
14	import { findingsPointer, reviewBodyPointer } from "./surface.js";
15	import { ResultEnvelopeCodec, PriceMapCodec, TestSummaryCodec, noticeFindings } from "./schema.js";
16	import type { Finding, Findings, ResultEnvelope, TestSummary } from "./schema.js";
17	import { resolve, supportedVersions } from "./registry.js";
18	import type { GhApi } from "./gh.js";
19	import { runGhApi } from "./gh.js";
20	export type { GhApi } from "./gh.js";
21	import { fetchDiff, fetchPrCandidates, resolvePr } from "./pr.js";
22	
23	export interface PostInput {
24	  readonly repo: string;
25	  readonly headSha: string;
26	  readonly botLogin: string;
27	  readonly findingsPath: string;
28	  readonly envelopePath: string;
29	  readonly pricesPath: string;
30	  /** Whether `pricesPath` is a real caller-supplied price map or the bundled all-zero example
31	   *  standing in for an absent one — threaded to the render layer so cost shows N/A, not a false
32	   *  $0.00, when absent (SPEC §6.2). */
33	  readonly pricesProvided: boolean;
34	  readonly templatePath: string;
35	  readonly inlineTemplatePath: string;
36	  /** Overrides the envelope's route (SPEC §6.1) when set; otherwise the envelope is the source. */
37	  readonly route?: string;
38	  readonly headBranch?: string;
39	  readonly testReportPath?: string;
40	  readonly effort?: string;
41	  /** Workflow run URL, threaded into the sticky's LLM Disclosure aside (SPEC §5.1 item 6). */
42	  readonly runUrl?: string;
43	  /** Findings-json artifact URL — the marker's fallback on every surface (sticky, each inline
44	   *  comment, and the review body itself) when the embedded form is too large (SPEC §5.1 item 7,
45	   *  §5.2, issue #19). */
46	  readonly jsonUrl?: string;
47	  /** Preformatted UTC post time, leading the sticky's "**Reviewed** `<sha>` at <postedAt>" meta
48	   *  segment (issue #28) — computed by the caller (index.ts's post command) via `formatUtc`, not here,
49	   *  so `post()` stays a thin, testable pass-through of the timestamp into `render()`. */
50	  readonly postedAt?: string;
51	}
52	
53	const DEFAULT_MARKER = "<!-- code-review -->";
54	const MAX_SUGGESTION_LINES = 10;
55	
56	/** Count lines in a suggestion string (empty suggestion "" = 1 line — delete range). */
57	const countSuggestionLines = (text: string): number => text.split("\n").length;
58	
59	/** Extract and check suggestion blocks in a comment body, stripping those that are too long. */
60	const checkLongSuggestions = (
61	  comments: readonly InlineComment[],
62	): { readonly comments: readonly InlineComment[]; readonly longFiles: readonly string[] } => {
63	  const longFiles: string[] = [];
64	  const adjusted = comments.map((c) => {
65	    const match = /```suggestion\n([\s\S]*?)\n```/.exec(c.body);
66	    if (match?.[1] && countSuggestionLines(match[1]) > MAX_SUGGESTION_LINES) {
67	      longFiles.push(`${c.path}:${String(c.line)}`);
68	      return {
69	        ...c,
70	        body: c.body.replace(
71	          /```suggestion\n[\s\S]*?\n```/,
72	          "*(suggestion omitted — exceeds GitHub's ~10-line suggestion limit; see summary)*",
73	        ),
74	      };
75	    }
76	    return c;
77	  });
78	  return { comments: adjusted, longFiles };
79	};
80	
81	// Loaders below never throw on untrusted artifacts (SPEC §5.5) — malformed input degrades to a
82	// tagged result the caller renders as a notice, rather than crashing the post.
83	type FindingsLoadResult =
84	  | { readonly kind: "ok"; readonly findings: Findings }
85	  | { readonly kind: "corrupt" }
86	  | { readonly kind: "invalid-shape" }
87	  | { readonly kind: "unsupported-schema-version"; readonly version: string };
88	
89	const loadFindings = (path: string): FindingsLoadResult => {
90	  let raw: unknown;
91	  try {
92	    raw = JSON.parse(readFileSync(path, "utf-8")) as unknown;
93	  } catch {
94	    return { kind: "corrupt" };
95	  }
96	  const resolution = resolve("findings", raw);
97	  switch (resolution.kind) {
98	    case "ok":
99	      return { kind: "ok", findings: resolution.value };
100	    case "unsupported-version":
101	      return { kind: "unsupported-schema-version", version: resolution.version };
102	    case "invalid-shape":
103	    case "missing-version":
104	      return { kind: "invalid-shape" };
105	  }
106	};
107	
108	const noticeMessageFor = (result: Exclude<FindingsLoadResult, { kind: "ok" }>): string => {
109	  switch (result.kind) {
110	    case "corrupt":
111	      return "Review output was missing or malformed — the review did not complete. See the workflow run for logs.";
112	    case "invalid-shape":
113	      return "Review output was malformed — it did not conform to the findings schema. See the workflow run for logs.";
114	    case "unsupported-schema-version": {
115	      const supported = supportedVersions("findings")
116	        .map((minor) => `${minor}.x`)
117	        .join(", ");
118	      return `Review output declares schema_version "${result.version}", which this commenter does not support (supported: ${supported}). See the workflow run for logs.`;
119	    }
120	  }
121	};
122	
123	/** Load the result envelope; null on any read/decode failure (SPEC §5.5 — degrade, never crash). */
124	const loadEnvelope = (path: string): ResultEnvelope | null => {
125	  let raw: unknown;
126	  try {
127	    raw = JSON.parse(readFileSync(path, "utf-8")) as unknown;
128	  } catch {
129	    return null;
130	  }
131	  const decoded = ResultEnvelopeCodec.decode(raw);
132	  return decoded._tag === "Right" ? decoded.right : null;
133	};
134	
135	/** Load an optional test report; undefined (and a warning) on any read/decode failure — REQ-CO-9
136	 *  enrichment is optional and MUST degrade gracefully, never abort the post. */
137	const loadTestReport = (path: string): TestSummary | undefined => {
138	  let raw: unknown;
139	  try {
140	    raw = JSON.parse(readFileSync(path, "utf-8")) as unknown;
141	  } catch (err) {
142	    process.stderr.write(
143	      `Warning: could not read test report at ${path}: ${err instanceof Error ? err.message : String(err)} — omitting test panel\n`,
144	    );
145	    return undefined;
146	  }
147	  const decoded = TestSummaryCodec.decode(raw);
148	  if (decoded._tag === "Left") {
149	    process.stderr.write(
150	      `Warning: test report at ${path} does not match the expected shape — omitting test panel\n`,
151	    );
152	    return undefined;
153	  }
154	  return decoded.right;
155	};
156	
157	/** Parse an `html_url` field out of a `gh api` JSON response; a malformed or unexpected response
158	 *  degrades to undefined rather than throwing — a missing link must never fail the post (§5.5). */
159	const parseHtmlUrl = (raw: string): string | undefined => {
160	  try {
161	    const parsed = JSON.parse(raw) as { html_url?: unknown };
162	    return typeof parsed.html_url === "string" ? parsed.html_url : undefined;
163	  } catch {
164	    return undefined;
165	  }
166	};
167	
168	/** A single comment's position payload, shared by the batched review POST and the per-comment
169	 *  salvage POST below. */
170	const commentPayload = (c: InlineComment): Record<string, unknown> => ({
171	  path: c.path,
172	  line: c.line,
173	  side: c.side,
174	  ...(c.start_line !== undefined && c.start_side !== undefined
175	    ? { start_line: c.start_line, start_side: c.start_side }
176	    : {}),
177	  body: formatMarkdown(c.body),
178	});
179	
180	/** Post the inline review, pointing its body at the sticky (issue #11) when the sticky's URL is
181	 *  known, and prepending the precomputed findings-json marker (issue #19) so the review body carries
182	 *  it too. `comments[i]` is the rendered comment for finding `inDiff[i]` (1:1, same order). Returns
183	 *  the review's `html_url` (undefined on a malformed response), how many inline comments actually
184	 *  posted, and the findings whose comment GitHub rejected — so the caller can surface exactly those
185	 *  in the sticky (issue #57) and keep the disposition count truthful (issue #21). */
186	const postInlineReview = async (
187	  repo: string,
188	  prNumber: number,
189	  headSha: string,
190	  comments: readonly InlineComment[],
191	  inDiff: readonly Finding[],
192	  stickyUrl: string | undefined,
193	  marker: string,
194	  ghApi: GhApi,
195	): Promise<{
196	  readonly url: string | undefined;
197	  readonly inlinePosted: number;
198	  readonly unposted: readonly Finding[];
199	}> => {
200	  const pointer = reviewBodyPointer(headSha, stickyUrl, marker);
201	  const reviewBody = (withComments: boolean): string =>
202	    JSON.stringify({
203	      body: pointer,
204	      commit_id: headSha,
205	      event: "COMMENT",
206	      comments: withComments ? comments.map(commentPayload) : [],
207	    });
208	  const reviewsEndpoint = [`repos/${repo}/pulls/${String(prNumber)}/reviews`, "--input", "-"];
209	  try {
210	    const stdout = await ghApi(reviewsEndpoint, reviewBody(true));
211	    return { url: parseHtmlUrl(stdout), inlinePosted: comments.length, unposted: [] };
212	  } catch (err) {
213	    // The reviews endpoint is atomic: one comment on a position GitHub won't accept rejects the WHOLE
214	    // batch (issue #57). Rather than fail the job — or drop every comment — post the review body-only
215	    // (so the event + findings marker exist) and then re-post each comment individually, keeping the
216	    // ones GitHub accepts and collecting the finding behind each one it rejects for the caller to
217	    // surface in the sticky. Degrade, never crash (§5.5). A body-only review that itself fails
218	    // (comments.length === 0) is a genuine error and propagates.
219	    if (comments.length === 0) throw err;
220	    process.stderr.write(
221	      `Warning: the batched inline review on PR #${String(prNumber)} was rejected (${err instanceof Error ? err.message : String(err)}) — GitHub rejects the whole batch if any one comment's position is invalid; posting the review body-only, then each comment individually to keep the valid ones (issue #57)\n`,
222	    );
223	    const url = parseHtmlUrl(await ghApi(reviewsEndpoint, reviewBody(false)));
224	    const commentsEndpoint = [`repos/${repo}/pulls/${String(prNumber)}/comments`, "--input", "-"];
225	    const unposted: Finding[] = [];
226	    let inlinePosted = 0;
227	    for (const [i, c] of comments.entries()) {
228	      try {
229	        await ghApi(commentsEndpoint, JSON.stringify({ commit_id: headSha, ...commentPayload(c) }));
230	        inlinePosted += 1;
231	      } catch (e) {
232	        const finding = inDiff[i];
233	        if (finding) unposted.push(finding);
234	        process.stderr.write(
235	          `Warning: inline comment on ${c.path}:${String(c.line)} rejected (${e instanceof Error ? e.message : String(e)}) — surfacing that finding in the sticky instead (issue #57)\n`,
236	        );
237	      }
238	    }
239	    return { url, inlinePosted, unposted };
240	  }
241	};
242	
243	const findBotComment = async (
244	  repo: string,
245	  prNumber: number,
246	  botLogin: string,
247	  marker: string,
248	  ghApi: GhApi,
249	): Promise<{ readonly id: number; readonly body: string } | null> => {
250	  const stdout = await ghApi(
251	    [
252	      `repos/${repo}/issues/${String(prNumber)}/comments`,
253	      "--paginate",
254	      "--jq",
255	      ".[] | select(.user.login == env.CODE_REVIEW_BOT_LOGIN and (.body | startswith(env.CODE_REVIEW_MARKER))) | {id: .id, body: .body}",
256	    ],
257	    undefined,
258	    { CODE_REVIEW_BOT_LOGIN: botLogin, CODE_REVIEW_MARKER: marker },
259	  );
260	  const lines = stdout.trim().split("\n").filter(Boolean);
261	  if (lines.length === 0) return null;
262	  const last = lines[lines.length - 1] ?? null;
263	  if (last === null) return null;
264	  const parsed = JSON.parse(last) as { id: number; body: string };
265	  return { id: parsed.id, body: parsed.body };
266	};
267	
268	/** Parse an issue-comment create/patch response for `id`/`html_url`; malformed responses degrade
269	 *  to null rather than throwing (§5.5, issue #11 ROBUSTNESS — a missing link must never fail the
270	 *  post). */
271	const parseCommentRef = (
272	  raw: string,
273	): { readonly id: number; readonly html_url: string } | null => {
274	  try {
275	    const parsed = JSON.parse(raw) as { id?: unknown; html_url?: unknown };
276	    return typeof parsed.id === "number" && typeof parsed.html_url === "string"
277	      ? { id: parsed.id, html_url: parsed.html_url }
278	      : null;
279	  } catch {
280	    return null;
281	  }
282	};
283	
284	const patchComment = async (
285	  repo: string,
286	  commentId: number,
287	  body: string,
288	  ghApi: GhApi,
289	): Promise<{ readonly html_url: string } | null> => {
290	  const stdout = await ghApi(
291	    [`repos/${repo}/issues/comments/${String(commentId)}`, "--input", "-"],
292	    JSON.stringify({ body }),
293	  );
294	  // Only `html_url` is needed here — the id is already known by the caller — so this doesn't
295	  // require `id` in the response the way parseCommentRef (used for a brand-new comment) does.
296	  const htmlUrl = parseHtmlUrl(stdout);
297	  return htmlUrl !== undefined ? { html_url: htmlUrl } : null;
298	};
299	
300	const postComment = async (
301	  repo: string,
302	  prNumber: number,
303	  body: string,
304	  ghApi: GhApi,
305	): Promise<{ readonly id: number; readonly html_url: string } | null> => {
306	  const stdout = await ghApi(
307	    [`repos/${repo}/issues/${String(prNumber)}/comments`, "--input", "-"],
308	    JSON.stringify({ body }),
309	  );
310	  return parseCommentRef(stdout);
311	};
312	
313	/** Upsert the sticky summary — trust by author identity (bot login), not marker alone (§5.3).
314	 *  Returns the sticky's id + `html_url` (url undefined on a malformed response) so the caller can
315	 *  re-patch it with a link to the review once posted (issue #11). Returns null only when a *new*
316	 *  comment's response couldn't be parsed at all — there is then no id to re-patch with. */
317	const upsertSticky = async (
318	  repo: string,
319	  prNumber: number,
320	  existing: { readonly id: number; readonly body: string } | null,
321	  body: string,
322	  ghApi: GhApi,
323	): Promise<{ readonly id: number; readonly url: string | undefined } | null> => {
324	  if (existing !== null) {
325	    const patched = await patchComment(repo, existing.id, body, ghApi);
326	    process.stderr.write(
327	      `Updated sticky comment #${String(existing.id)} on PR #${String(prNumber)}\n`,
328	    );
329	    return { id: existing.id, url: patched?.html_url };
330	  }
331	  const posted = await postComment(repo, prNumber, body, ghApi);
332	  process.stderr.write(`Posted new sticky comment on PR #${String(prNumber)}\n`);
333	  return posted ? { id: posted.id, url: posted.html_url } : null;
334	};
335	
336	/** A non-dismissed bot-authored review. Only its id is needed — every prior bot review is
337	 *  superseded regardless of which commit it reviewed (issue #53). */
338	interface BotReviewRef {
339	  readonly id: number;
340	}
341	
342	const isBotReview = (r: unknown): r is { id: number; user: { login: string }; state: string } =>
343	  typeof r === "object" &&
344	  r !== null &&
345	  typeof (r as { id?: unknown }).id === "number" &&
346	  typeof (r as { state?: unknown }).state === "string" &&
347	  typeof (r as { user?: { login?: unknown } }).user?.login === "string";
348	
349	/** List the PR's non-dismissed bot-authored reviews. */
350	const fetchBotReviews = async (
351	  repo: string,
352	  prNumber: number,
353	  botLogin: string,
354	  ghApi: GhApi,
355	): Promise<readonly BotReviewRef[]> => {
356	  const stdout = await ghApi([`repos/${repo}/pulls/${String(prNumber)}/reviews`, "--paginate"]);
357	  let reviews: unknown;
358	  try {
359	    reviews = JSON.parse(stdout || "[]");
360	  } catch {
361	    return [];
362	  }
363	  if (!Array.isArray(reviews)) return [];
364	  return reviews
365	    .filter(isBotReview)
366	    .filter((r) => r.user.login === botLogin && r.state !== "DISMISSED")
367	    .map((r) => ({ id: r.id }));
368	};
369	
370	/** Dismiss superseded bot-authored reviews (REC-CO-2). Failures are logged, never fail the job. */
371	const dismissReviews = async (
372	  repo: string,
373	  prNumber: number,
374	  ids: readonly number[],
375	  ghApi: GhApi,
376	): Promise<void> => {
377	  for (const id of ids) {
378	    try {
379	      await ghApi(
380	        [
381	          `repos/${repo}/pulls/${String(prNumber)}/reviews/${String(id)}/dismissals`,
382	          "-X",
383	          "PUT",
384	          "--input",
385	          "-",
386	        ],
387	        JSON.stringify({ message: "Superseded by a new review for an updated commit." }),
388	      );
389	    } catch (err) {
390	      process.stderr.write(
391	        `Warning: failed to dismiss prior review #${String(id)} on PR #${String(prNumber)}: ${err instanceof Error ? err.message : String(err)}\n`,
392	      );
393	    }
394	  }
395	};
396	
397	/** GraphQL: list a PR's review-thread comments — author + whether already minimized — enough to find
398	 *  the bot's own inline comments left by prior reviews. Capped at the first 100 threads (×100 comments
399	 *  each); `pageInfo.hasNextPage` flags a PR that exceeds the cap. */
400	const REVIEW_THREAD_COMMENTS_QUERY =
401	  "query($owner:String!,$name:String!,$pr:Int!){repository(owner:$owner,name:$name){pullRequest(number:$pr){reviewThreads(first:100){pageInfo{hasNextPage}nodes{comments(first:100){nodes{id isMinimized author{login}}}}}}}}";
402	
403	/** GraphQL: hide one comment as OUTDATED. Reversible — minimized, not deleted. */
404	const MINIMIZE_COMMENT_MUTATION =
405	  "mutation($id:ID!){minimizeComment(input:{subjectId:$id,classifier:OUTDATED}){minimizedComment{isMinimized}}}";
406	
407	/** The comment's node id when it is a bot-authored, not-yet-minimized inline comment; null otherwise.
408	 *  GraphQL reports the bare login (`github-actions`), so the bot login is matched with and without the
409	 *  REST `[bot]` suffix. Which SHA it was authored against no longer matters — the caller snapshots the
410	 *  set BEFORE posting the fresh review, so every match is by definition a prior (stale) comment. Pure. */
411	const priorBotCommentId = (c: unknown, logins: readonly string[]): string | null => {
412	  if (typeof c !== "object" || c === null) return null;
413	  const o = c as { id?: unknown; isMinimized?: unknown; author?: { login?: unknown } | null };
414	  const login = o.author?.login;
415	  return typeof o.id === "string" &&
416	    o.isMinimized !== true &&
417	    typeof login === "string" &&
418	    logins.includes(login)
419	    ? o.id
420	    : null;
421	};
422	
423	/** Parse the review-threads response into the bot's not-yet-minimized inline comment ids, degrading
424	 *  to an empty list on any malformed shape (§5.5), and flagging whether the 100-thread cap was hit.
425	 *  Pure. */
426	const priorBotCommentIds = (
427	  raw: string,
428	  botLogin: string,
429	): { readonly ids: readonly string[]; readonly truncated: boolean } => {
430	  let parsed: unknown;
431	  try {
432	    parsed = JSON.parse(raw);
433	  } catch {
434	    return { ids: [], truncated: false };
435	  }
436	  const conn = (
437	    parsed as {
438	      data?: {
439	        repository?: {
440	          pullRequest?: {
441	            reviewThreads?: { nodes?: unknown; pageInfo?: { hasNextPage?: unknown } };
442	          };
443	        };
444	      };
445	    }
446	  ).data?.repository?.pullRequest?.reviewThreads;
447	  const truncated = conn?.pageInfo?.hasNextPage === true;
448	  const nodes = conn?.nodes;
449	  if (!Array.isArray(nodes)) return { ids: [], truncated };
450	  const logins = [botLogin.replace(/\[bot\]$/, ""), botLogin];
451	  const ids = nodes.flatMap((t) => {
452	    const cnodes = (t as { comments?: { nodes?: unknown } }).comments?.nodes;
453	    return Array.isArray(cnodes)
454	      ? cnodes.map((c) => priorBotCommentId(c, logins)).filter((id): id is string => id !== null)
455	      : [];
456	  });
457	  return { ids, truncated };
458	};
459	
460	/** Snapshot the bot's own not-yet-minimized inline review comments currently on the PR — the stale
461	 *  threads left by prior reviews (issue #31/#53). Called BEFORE the fresh review is posted, so the set
462	 *  is exactly the prior comments (whether on a superseded commit or an earlier review of this same
463	 *  SHA) and never the fresh ones. Best-effort: any listing failure logs and returns []. */
464	const listPriorBotCommentIds = async (
465	  repo: string,
466	  prNumber: number,
467	  botLogin: string,
468	  ghApi: GhApi,
469	): Promise<readonly string[]> => {
470	  const slash = repo.indexOf("/");
471	  if (slash <= 0) return [];
472	  const owner = repo.slice(0, slash);
473	  const name = repo.slice(slash + 1);
474	  let raw: string;
475	  try {
476	    raw = await ghApi([
477	      "graphql",
478	      "-f",
479	      `query=${REVIEW_THREAD_COMMENTS_QUERY}`,
480	      "-f",
481	      `owner=${owner}`,
482	      "-f",
483	      `name=${name}`,
484	      "-F",
485	      `pr=${String(prNumber)}`,
486	    ]);
487	  } catch (err) {
488	    process.stderr.write(
489	      `Warning: could not list review threads to minimize stale comments on PR #${String(prNumber)}: ${err instanceof Error ? err.message : String(err)}\n`,
490	    );
491	    return [];
492	  }
493	  const { ids, truncated } = priorBotCommentIds(raw, botLogin);
494	  if (truncated) {
495	    process.stderr.write(
496	      `Note: PR #${String(prNumber)} has more than 100 review threads — only the first 100 were scanned for stale bot comments\n`,
497	    );
498	  }
499	  return ids;
500	};
501	
502	/** Minimize (as OUTDATED, reversibly) the given bot inline comment node ids — the pre-post snapshot of
503	 *  stale threads — so a re-reviewed PR doesn't accumulate them (issue #31/#53). Best-effort: any
504	 *  minimize failure is logged and never fails the post. */
505	const minimizeComments = async (
506	  prNumber: number,
507	  ids: readonly string[],
508	  ghApi: GhApi,
509	): Promise<void> => {
510	  let minimized = 0;
511	  for (const id of ids) {
512	    try {
513	      await ghApi(["graphql", "-f", `query=${MINIMIZE_COMMENT_MUTATION}`, "-f", `id=${id}`]);
514	      minimized += 1;
515	    } catch (err) {
516	      process.stderr.write(
517	        `Warning: failed to minimize a stale review comment on PR #${String(prNumber)}: ${err instanceof Error ? err.message : String(err)}\n`,
518	      );
519	    }
520	  }
521	  if (minimized > 0) {
522	    process.stderr.write(
523	      `Minimized ${String(minimized)} stale inline comment(s) from superseded reviews on PR #${String(prNumber)}\n`,
524	    );
525	  }
526	};
