528	export const post = async (input: PostInput, ghApi: GhApi = runGhApi): Promise<void> => {
529	  // Phase 1 (CO-R3): reads, decodes, diff validation, rendering — no writes yet.
530	  const candidates = await fetchPrCandidates(input.repo, input.headSha, ghApi);
531	  const resolution = resolvePr(candidates, input.headBranch);
532	  if (resolution.kind === "none") {
533	    process.stderr.write(`No open PR for ${input.headSha} — nothing to post\n`);
534	    process.exit(0);
535	  }
536	  if (resolution.kind === "not-open") {
537	    process.stderr.write(
538	      `PR #${String(resolution.prNumber)} for ${input.headSha} is not open (state: ${resolution.state}) — nothing to post\n`,
539	    );
540	    process.exit(0);
541	  }
542	  const prNumber = resolution.prNumber;
543	
544	  const diff = await fetchDiff(input.repo, prNumber, ghApi);
545	  const existingSticky = await findBotComment(
546	    input.repo,
547	    prNumber,
548	    input.botLogin,
549	    DEFAULT_MARKER,
550	    ghApi,
551	  );
552	
553	  const prices = JSON.parse(readFileSync(input.pricesPath, "utf-8")) as unknown;
554	  const decodedPrices = PriceMapCodec.decode(prices);
555	  if (decodedPrices._tag === "Left") {
556	    throw new Error(`Price map at ${input.pricesPath} does not match the expected shape`);
557	  }
558	  const template = readFileSync(input.templatePath, "utf-8");
559	  const inlineTemplate = readFileSync(input.inlineTemplatePath, "utf-8");
560	
561	  const renderNotice = (message: string): string =>
562	    formatMarkdown(
563	      render({
564	        findings: noticeFindings(`### ⚠️ ${message}`),
565	        envelope: null,
566	        prices: decodedPrices.right,
567	        pricesProvided: input.pricesProvided,
568	        template,
569	        route: input.route,
570	        reviewedSha: input.headSha,
571	        effort: input.effort,
572	        runUrl: input.runUrl,
573	        jsonUrl: input.jsonUrl,
574	        postedAt: input.postedAt,
575	      }),
576	    );
577	
578	  if (isEmptyDiff(diff)) {
579	    await upsertSticky(
580	      input.repo,
581	      prNumber,
582	      existingSticky,
583	      renderNotice("The diff for this PR is empty — nothing to review."),
584	      ghApi,
585	    );
586	    process.exit(0);
587	  }
588	
589	  const findingsResult = loadFindings(input.findingsPath);
590	  if (findingsResult.kind !== "ok") {
591	    await upsertSticky(
592	      input.repo,
593	      prNumber,
594	      existingSticky,
595	      renderNotice(noticeMessageFor(findingsResult)),
596	      ghApi,
597	    );
598	    process.exit(0);
599	  }
600	  const findings = findingsResult.findings;
601	
602	  const envelope = loadEnvelope(input.envelopePath);
603	  const testReport = input.testReportPath ? loadTestReport(input.testReportPath) : undefined;
604	
605	  if (envelope === null) {
606	    const body = formatMarkdown(
607	      render({
608	        findings,
609	        envelope: null,
610	        prices: decodedPrices.right,
611	        pricesProvided: input.pricesProvided,
612	        template,
613	        route: input.route,
614	        reviewedSha: input.headSha,
615	        effort: input.effort,
616	        testReport,
617	        inlineDisposition: { kind: "no-envelope" },
618	        runUrl: input.runUrl,
619	        jsonUrl: input.jsonUrl,
620	        postedAt: input.postedAt,
621	      }),
622	    );
623	    await upsertSticky(input.repo, prNumber, existingSticky, body, ghApi);
624	    process.stderr.write(
625	      "Result envelope missing or malformed — posted sticky summary without usage/cost data; no inline review\n",
626	    );
627	    process.exit(0);
628	  }
629	
630	  // Issue #19 + review fix #5: base64-encode the whole-document marker ONCE and reuse it on the two
631	  // single-per-review surfaces (both sticky renders, the review body). Each inline comment instead
632	  // embeds only its OWN finding (issue #31) — buildInlineComments derives that per-finding marker
633	  // itself from `findings` below, rather than reusing this whole-document one.
634	  const findingsMarker = findingsPointer(findings, input.jsonUrl);
635	
636	  const {
637	    comments: rawComments,
638	    strays,
639	    inDiff,
640	  } = buildInlineComments(findings.findings, diff, {
641	    inlineTemplate,
642	    models: envelope.models.map((m) => m.model),
643	    findings,
644	    jsonUrl: input.jsonUrl,
645	  });
646	  const { comments, longFiles } = checkLongSuggestions(rawComments);
647	  for (const wf of longFiles) {
648	    process.stderr.write(
649	      `Warning: suggestion in ${wf} exceeds ${String(MAX_SUGGESTION_LINES)} lines — omitted from inline to avoid 422\n`,
650	    );
651	  }
652	
653	  // The bot's prior reviews (identity via the reviews API `commit_id`), fetched to supersede every
654	  // one of them — including any already on THIS head SHA — before posting the fresh review below.
655	  // We ran the review agent and paid for it, so its result must be surfaced: a re-request (or an
656	  // incidental CI re-run) on the same commit dismisses the stale review and posts the new one rather
657	  // than being skipped (issue #53). Fetched unconditionally now that a review is always posted (#43).
658	  const botReviews = await fetchBotReviews(input.repo, prNumber, input.botLogin, ghApi);
659	
660	  // Issue #21: the "posted — see the review" disposition is constructed ONLY from the actual
661	  // postInlineReview result below, never optimistically — a review that doesn't yet exist (or
662	  // never will, if this process dies before posting it) must never be claimed. Everything knowable
663	  // from reads alone (no-in-diff-findings) is truthful up front and stays as-is.
664	  const initialDisposition: InlineDisposition | undefined =
665	    comments.length === 0 && strays.length > 0 ? { kind: "none-in-diff" } : undefined;
666	
667	  const commonRenderInput: Omit<RenderInput, "inlineDisposition" | "reviewUrl"> = {
668	    findings,
669	    envelope,
670	    prices: decodedPrices.right,
671	    pricesProvided: input.pricesProvided,
672	    template,
673	    route: input.route,
674	    reviewedSha: input.headSha,
675	    effort: input.effort,
676	    testReport,
677	    severityCounts: computeSeverityCounts(findings.findings),
678	    strays,
679	    runUrl: input.runUrl,
680	    jsonUrl: input.jsonUrl,
681	    findingsPointer: findingsMarker,
682	    postedAt: input.postedAt,
683	  };
684	  const longFilesNote =
685	    longFiles.length > 0
686	      ? `\n\n---\n\n> **Note:** ${String(longFiles.length)} suggestion(s) exceeded GitHub's ~10-line inline suggestion limit and were omitted from the inline comments; the affected findings remain in the review.\n`
687	      : "";
688	  // Renders the sticky body; called twice (issue #11) — once before the review exists (no
689	  // disposition claim beyond what reads already confirmed), once after (with the confirmed
690	  // disposition + reviewUrl) to report the truth and link the sticky back to the review.
691	  const renderBody = (
692	    inlineDisposition: InlineDisposition | undefined,
693	    reviewUrl?: string,
694	    straysOverride?: readonly Finding[],
695	    unanchoredCount?: number,
696	  ): string =>
697	    formatMarkdown(
698	      render({
699	        ...commonRenderInput,
700	        ...(straysOverride ? { strays: straysOverride } : {}),
701	        ...(unanchoredCount !== undefined ? { unanchoredCount } : {}),
702	        inlineDisposition,
703	        reviewUrl,
704	      }) + longFilesNote,
705	    );
706	
707	  // Phase 2 (CO-R3): writes — sticky first, inline second; failure exits non-zero.
708	  const stickyRef = await upsertSticky(
709	    input.repo,
710	    prNumber,
711	    existingSticky,
712	    renderBody(initialDisposition),
713	    ghApi,
714	  );
715	
716	  // Issue #43: a COMMENT review is posted on EVERY run, even with no in-diff comments, so tooling and
717	  // agents get a review event every time — its body points at the sticky (for humans) and carries the
718	  // findings-JSON marker (for agents).
719	
720	  // Issue #31/#53: snapshot the bot's existing inline comments BEFORE posting the fresh review, so the
721	  // stale ones can be minimized afterward without touching the fresh ones. Timing — not the comment's
722	  // commit SHA — separates stale from fresh: everything present now is from a prior review (on a
723	  // superseded commit OR an earlier review of this same SHA); the fresh comments are posted below.
724	  const priorInlineComments = await listPriorBotCommentIds(
725	    input.repo,
726	    prNumber,
727	    input.botLogin,
728	    ghApi,
729	  );
730	
731	  // Post the fresh review FIRST, THEN supersede the prior ones (REC-CO-2 + issue #53): posting before
732	  // dismissing means the PR is never left without a review even if the process dies between the two —
733	  // a re-review of the same commit dismisses the stale review only after its replacement exists.
734	  const {
735	    url: reviewUrl,
736	    inlinePosted,
737	    unposted,
738	  } = await postInlineReview(
739	    input.repo,
740	    prNumber,
741	    input.headSha,
742	    comments,
743	    inDiff,
744	    stickyRef?.url,
745	    findingsMarker,
746	    ghApi,
747	  );
748	  process.stderr.write(
749	    `Posted a review with ${String(inlinePosted)} inline comment(s) on PR #${String(prNumber)}\n`,
750	  );
751	
752	  // Supersede EVERY prior bot review — those on other commits and any already on this head SHA.
753	  // Best-effort: a dismissal that fails leaves a stale review beside the fresh one (logged), which
754	  // beats failing the job now that the fresh review is already posted. Concurrent runs on the same
755	  // commit are bounded by the workflow's concurrency group; GitHub itself tolerates multiple reviews.
756	  const priorReviewIds = botReviews.map((r) => r.id);
757	  if (priorReviewIds.length > 0) {
758	    await dismissReviews(input.repo, prNumber, priorReviewIds, ghApi);
759	  }
760	
761	  // Issue #31/#53: minimize the pre-post snapshot — the stale threads from the reviews just
762	  // superseded — so a re-reviewed PR doesn't accumulate them. The fresh review's comments were posted
763	  // after the snapshot, so they are untouched. Best-effort — the fresh review is already posted.
764	  await minimizeComments(prNumber, priorInlineComments, ghApi);
765	
766	  // Issue #11/#21/#57: now that postInlineReview has resolved, re-render the sticky to the truth.
767	  // - `inlinePosted > 0` → "posted N" + the review link (N is the count that ACTUALLY posted, so a
768	  //   partial #57 salvage reports only the anchored ones).
769	  // - `unposted` (issue #57) → the in-diff findings GitHub rejected are appended to the real
770	  //   out-of-diff strays so no finding is lost to human view; `unanchoredCount` drives the section's
771	  //   note. When NONE anchored, the disposition says the inline surface was unavailable, never a
772	  //   false "posted" (issue #21).
773	  // - Neither → a body-only review with no in-diff comments (issue #43) keeps the initial sticky.
774	  // Best-effort — the sticky and review are already posted, so a failure here must never fail the job.
775	  const unanchoredCount = unposted.length;
776	  const finalStrays = unanchoredCount > 0 ? [...unposted, ...strays] : strays;
777	  const finalDisposition: InlineDisposition | undefined =
778	    inlinePosted > 0
779	      ? { kind: "posted", count: inlinePosted, sha: input.headSha }
780	      : unanchoredCount > 0
781	        ? { kind: "inline-unavailable" }
782	        : initialDisposition;
783	  if (stickyRef !== null && (inlinePosted > 0 || unanchoredCount > 0)) {
784	    try {
785	      await patchComment(
786	        input.repo,
787	        stickyRef.id,
788	        renderBody(finalDisposition, reviewUrl, finalStrays, unanchoredCount),
789	        ghApi,
790	      );
791	      process.stderr.write(
792	        `Updated sticky comment #${String(stickyRef.id)} to reflect the review\n`,
793	      );
794	    } catch (err) {
795	      process.stderr.write(
796	        `Warning: failed to update the sticky summary after the review: ${err instanceof Error ? err.message : String(err)}\n`,
797	      );
798	    }
799	  }
800	};
