1	// Inline review payload builder. Validates findings against the diff,
2	// builds the GitHub reviews API comments[] array, and demotes strays.
3	
4	import { Eta } from "eta";
5	import { partitionFindings, indexDiff, defaultSide } from "./diff.js";
6	import { severityEmoji, findingPointer, projectPatch, formatConfidence } from "./surface.js";
7	import type { Finding, Findings } from "./schema.js";
8	import type { InlineComment, InlineResult } from "./types.js";
9	
10	/** Backtick-wrapped, `/`-joined model names for the disclosure line (issue #16), falling back to
11	 *  a plain phrase when no models are known. */
12	const formatModels = (models: readonly string[]): string =>
13	  models.length > 0 ? models.map((m) => `\`${m}\``).join("/") : "an AI model";
14	
15	/** Render a finding's inline comment body via the inline Eta template (bundled by default — see
16	 *  resolveInlineTemplatePath, index.ts). The template is the SSOT for all body text — severity
17	 *  header, description, recommendation, the projected patch block, and the [!TIP] disclosure fold;
18	 *  TS supplies only data. The patch is projected here (never a `suggestion` field — that field is
19	 *  gone as of schema 0.4). */
20	const renderCommentBody = (
21	  f: Finding,
22	  eta: Eta,
23	  template: string,
24	  modelsText: string,
25	  jsonUrl: string | undefined,
26	  pointer: string,
27	): string =>
28	  // Eta.renderString returns string | Promise<string>; with autoTrim:false it's always sync.
29	  // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-assertion
30	  eta.renderString(template, {
31	    ...f,
32	    patchProjection: projectPatch(f.patch),
33	    severityEmoji,
34	    formatConfidence,
35	    modelsText,
36	    jsonUrl: jsonUrl ?? null,
37	    findingsPointer: pointer,
38	  }) as string;
39	
40	/** Extra context threaded into each inline comment beyond the finding itself. */
41	export interface InlineContext {
42	  /** Eta template for each comment's body — bundled by default (index.ts's
43	   *  resolveInlineTemplatePath), overridable via --inline-template. */
44	  readonly inlineTemplate: string;
45	  /** Model name(s) that produced the review, for the template's disclosure line (issue #16). */
46	  readonly models?: readonly string[];
47	  /** Findings-json artifact URL — the marker's fallback when the embedded form is too large (#19). */
48	  readonly jsonUrl?: string;
49	  /** The full findings document — each in-diff comment embeds only its OWN finding (issue #31), but
50	   *  needs the document's `schema_version` to do so; omitted when the caller has no document at all
51	   *  (each comment's marker is then omitted too). */
52	  readonly findings?: Findings;
53	}
54	
55	/** Build the GitHub reviews API comments[] array from in-diff findings. Strays are demoted. */
56	export const buildInlineComments = (
57	  findings: readonly Finding[],
58	  diff: string,
59	  context: InlineContext,
60	): InlineResult => {
61	  const { inlineTemplate, models = [], jsonUrl, findings: fullFindings } = context;
62	  const index = indexDiff(diff);
63	  const { inDiff, strays } = partitionFindings(findings, index);
64	  const eta = new Eta({ autoTrim: false });
65	  const modelsText = formatModels(models);
66	
67	  const comments: InlineComment[] = inDiff.map((f) => {
68	    const pointer = fullFindings ? findingPointer(f, fullFindings.schema_version, jsonUrl) : "";
69	    const comment: InlineComment = {
70	      path: f.path,
71	      line: f.end_line,
72	      side: defaultSide(f.side),
73	      body: renderCommentBody(f, eta, inlineTemplate, modelsText, jsonUrl, pointer),
74	    };
75	    if (f.start_line < f.end_line) {
76	      return {
77	        ...comment,
78	        start_line: f.start_line,
79	        start_side: defaultSide(f.side),
80	      };
81	    }
82	    return comment;
83	  });
84	
85	  return { comments, strays, inDiff };
86	};
87	
88	/** Render the demoted (stray) findings as a markdown section for the summary. */
89	export const renderStraysSection = (strays: readonly Finding[]): string => {
90	  if (strays.length === 0) return "";
91	
92	  const items = strays.map(
93	    (f) => `- **${f.severity}** · \`${f.path}:${String(f.start_line)}\` — ${f.title}`,
94	  );
95	
96	  return [
97	    "",
98	    "---",
99	    "",
100	    "#### ⚠️ Findings on lines not in the diff (demoted to summary)",
101	    "",
102	    ...items,
103	  ].join("\n");
104	};
