149	const mkMockGhApi = (
150	  responses: ReadonlyArray<{
151	    readonly match: (args: readonly string[]) => boolean;
152	    readonly response: string;
153	  }>,
154	): { readonly api: GhApi; readonly calls: () => readonly RecordedCall[] } => {
155	  const calls: RecordedCall[] = [];
156	  const api: GhApi = (args, stdin, env) => {
157	    calls.push({ args: [...args], stdin, env });
158	    for (const r of responses) {
159	      if (r.match(args)) return Promise.resolve(r.response);
160	    }
161	    return Promise.reject(new Error(`Unexpected gh api call: ${args.join(" ")}`));
162	  };
163	  return { api, calls: () => calls };
164	};
